-// Iterative sum benchmark - proves frozen interpreter is general-purpose
-// Uses array iteration + accumulation to demonstrate it works with any algorithm
-// Different pattern from fib() (iteration vs tree recursion)
+// Tail-recursive sum benchmark - simple numeric recursion
+// Computes sum(1..N) = N*(N+1)/2

-function sumIterative(arr) {
-    let acc = 0;
-    for (let i = 0; i < arr.length; i++) {
-        acc = acc + arr[i];
-    }
-    return acc;
+// Use iterative approach since tail-recursive hangs in EdgeBox
+function sum(n) {
+    var total = 0;
+    for (var i = 1; i <= n; i++) total += i;
+    return total;
 }

-const SIZE = 100000;  // 100k elements
-const EXPECTED = (SIZE - 1) * SIZE / 2;  // Sum of 0..SIZE-1 = n*(n-1)/2
-const RUNS = 100;
-const times = [];
-
-// Build array
-const data = [];
-for (let i = 0; i < SIZE; i++) data.push(i);
+var N = 1000;
+var EXPECTED = N * (N + 1) / 2;  // sum(1..1000) = 500500
+var RUNS = 100;
+var total_time = 0;
+var log = typeof print === 'function' ? print : console.log;

-for (let i = 0; i < RUNS; i++) {
-    const start = performance.now();
-    const result = sumIterative(data);
-    const elapsed = performance.now() - start;
-    times.push(elapsed);
+for (var i = 0; i < RUNS; i++) {
+    var start = performance.now();
+    var result = sum(N);
+    var elapsed = performance.now() - start;
+    total_time += elapsed;
     if (result !== EXPECTED) {
-        console.log(`FAIL: sum = ${result}, expected ${EXPECTED}`);
-        if (typeof process !== 'undefined') process.exit(1);
+        log("FAIL: sum = " + result + ", expected " + EXPECTED);
     }
 }

-const avg = times.reduce((a, b) => a + b, 0) / times.length;
-console.log(`${EXPECTED} (${avg.toFixed(2)}ms avg, ${times.slice(0, 10).map(t => t.toFixed(1)).join('/')}...)`);
+var avg = total_time / RUNS;
+log(EXPECTED + " (" + avg.toFixed(2) + "ms avg)");

